#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007U
#define MAXN 5000000
static unsigned char is_composite[MAXN + 1];
static int prime_cnt[MAXN + 1];
static unsigned int pref[MAXN + 1];

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    int *queries = (int*)malloc(T * sizeof(int));
    int maxN = 0;
    for(int i=0;i<T;i++){
        scanf("%d", &queries[i]);
        if(queries[i] > maxN) maxN = queries[i];
    }
    // sieve
    prime_cnt[0] = prime_cnt[1] = 0;
    for(int i=2;i<=maxN;i++){
        if(!is_composite[i]){
            for(long long j=1LL*i*i;j<=maxN;j+=i) is_composite[j]=1;
        }
        prime_cnt[i] = prime_cnt[i-1] + (!is_composite[i]);
    }
    // prefix product
    pref[0] = 1;
    for(int i=1;i<=maxN;i++){
        unsigned long long mult = (unsigned long long)pref[i-1] * (prime_cnt[i] + 1);
        pref[i] = (unsigned int)(mult % MOD);
    }
    // answer queries
    for(int i=0;i<T;i++){
        printf("%u\n", pref[queries[i]]);
    }
    free(queries);
    return 0;
}

