import java.io.*;
import java.util.*;

public class Main {
    static final int MOD = 1_000_000_007;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        int[] queries = new int[T];
        int maxN = 0;
        for (int i = 0; i < T; i++) {
            queries[i] = fs.nextInt();
            if (queries[i] > maxN) maxN = queries[i];
        }
        boolean[] comp = new boolean[maxN + 1];
        int[] primeCnt = new int[maxN + 1];
        for (int i = 2; i * i <= maxN; i++) {
            if (!comp[i]) {
                for (int j = i * i; j <= maxN; j += i) comp[j] = true;
            }
        }
        for (int i = 2; i <= maxN; i++) {
            primeCnt[i] = primeCnt[i - 1] + (!comp[i] ? 1 : 0);
        }
        int[] pref = new int[maxN + 1];
        pref[0] = 1;
        for (int i = 1; i <= maxN; i++) {
            long val = (long) pref[i - 1] * (primeCnt[i] + 1) % MOD;
            pref[i] = (int) val;
        }
        StringBuilder sb = new StringBuilder();
        for (int n : queries) {
            sb.append(pref[n]).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner for large input
    static class FastScanner {
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private final InputStream in;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

