const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
const queries = new Array(T);
let maxN = 0;
for (let i = 0; i < T; i++) {
  const n = input[idx++];
  queries[i] = n;
  if (n > maxN) maxN = n;
}
// sieve
const isComp = new Uint8Array(maxN + 1);
const primeCnt = new Uint32Array(maxN + 1);
for (let i = 2; i * i <= maxN; i++) {
  if (!isComp[i]) {
    for (let j = i * i; j <= maxN; j += i) isComp[j] = 1;
  }
}
for (let i = 2; i <= maxN; i++) {
  primeCnt[i] = primeCnt[i - 1] + (isComp[i] ? 0 : 1);
}
const pref = new Uint32Array(maxN + 1);
pref[0] = 1;
for (let i = 1; i <= maxN; i++) {
  const mult = (BigInt(pref[i - 1]) * BigInt(primeCnt[i] + 1)) % MOD;
  pref[i] = Number(mult);
}
let out = '';
for (let i = 0; i < T; i++) {
  out += pref[queries[i]] + (i + 1 === T ? '' : '\n');
